import React, { useEffect, useState } from "react";
import { supabase } from "../supabaseClient";
import { 
  LogOut, RefreshCcw, MapPin, Clock, Phone, 
  Smartphone, Car, Navigation, CheckCircle, 
  XCircle, Send, LayoutDashboard, ListFilter
} from "lucide-react";

const Dashboard = ({ session }) => {
  const [rides, setRides] = useState([]);
  const [isRefreshing, setIsRefreshing] = useState(false);
  const [filter, setFilter] = useState("all");

  useEffect(() => {
    fetchRides();
    const channel = supabase
      .channel('realtime-rides')
      .on('postgres_changes', { event: '*', schema: 'public', table: 'rides' }, () => {
        fetchRides(); // Refresh on any change
      })
      .subscribe();
    return () => supabase.removeChannel(channel);
  }, []);

  const fetchRides = async () => {
    setIsRefreshing(true);
    const { data } = await supabase
      .from("rides")
      .select("*")
      .order("created_at", { ascending: false });
    setRides(data || []);
    setTimeout(() => setIsRefreshing(false), 600);
  };

  const updateStatus = async (id, newStatus) => {
    const { error } = await supabase
      .from('rides')
      .update({ status: newStatus })
      .eq('id', id);
    if (error) alert(error.message);
    else fetchRides();
  };

  // Stats Logic
  const stats = {
    total: rides.length,
    pending: rides.filter(r => r.status === 'pending').length,
    today: rides.filter(r => r.ride_date === new Date().toISOString().split('T')[0]).length,
    completed: rides.filter(r => r.status === 'completed').length
  };

  // Filtered List
  const filteredRides = filter === "all" ? rides : rides.filter(r => r.status === filter);

  const handleLogout = () => supabase.auth.signOut();

  // --- Styles ---
  const styles = {
    container: { minHeight: "100vh", background: "#f8fafc", fontFamily: "'Inter', sans-serif", padding: "30px" },
    nav: { display: "flex", justifyContent: "space-between", alignItems: "center", background: "#fff", padding: "15px 30px", borderRadius: "16px", marginBottom: "30px", boxShadow: "0 4px 12px rgba(0,0,0,0.03)" },
    statsGrid: { display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(200px, 1fr))", gap: "20px", marginBottom: "30px" },
    statCard: { background: "#fff", padding: "20px", borderRadius: "16px", boxShadow: "0 4px 12px rgba(0,0,0,0.02)", borderLeft: "4px solid #e55a7b" },
    statusBadge: (status) => ({
      padding: "4px 12px", borderRadius: "20px", fontSize: "12px", fontWeight: "600",
      background: status === 'pending' ? '#fef3c7' : status === 'completed' ? '#dcfce7' : '#dbeafe',
      color: status === 'pending' ? '#d97706' : status === 'completed' ? '#15803d' : '#1e40af',
      textTransform: "capitalize"
    }),
    actionBtn: { padding: "8px", borderRadius: "8px", border: "1px solid #eee", cursor: "pointer", background: "#fff", transition: "0.2s" }
  };

  return (
    <div style={styles.container}>
      {/* Top Nav */}
      <nav style={styles.nav}>
        <h1 style={{ color: "#e55a7b", display: "flex", alignItems: "center", gap: "10px", margin: 0 }}>
          <Navigation /> PAHEL Admin
        </h1>
        <div style={{ display: "flex", alignItems: "center", gap: "20px" }}>
          <span style={{ fontSize: "14px", color: "#64748b" }}>{session.user.email}</span>
          <button onClick={handleLogout} style={{ background: "none", border: "none", color: "#ef4444", cursor: "pointer" }}><LogOut /></button>
        </div>
      </nav>

      {/* Stats Cards */}
      <div style={styles.statsGrid}>
        <div style={styles.statCard}><h3>{stats.total}</h3><p>Total Bookings</p></div>
        <div style={{...styles.statCard, borderLeftColor: "#f59e0b"}}><h3>{stats.pending}</h3><p>Pending Actions</p></div>
        <div style={{...styles.statCard, borderLeftColor: "#10b981"}}><h3>{stats.today}</h3><p>Today's Rides</p></div>
        <div style={{...styles.statCard, borderLeftColor: "#3b82f6"}}><h3>{stats.completed}</h3><p>Completed</p></div>
      </div>

      <div style={{ background: "#fff", borderRadius: "16px", padding: "25px", boxShadow: "0 4px 12px rgba(0,0,0,0.02)" }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "20px" }}>
          <div style={{ display: "flex", gap: "10px" }}>
            {['all', 'pending', 'confirmed', 'completed'].map(t => (
              <button key={t} onClick={() => setFilter(t)} style={{ padding: "8px 16px", borderRadius: "8px", border: filter === t ? "none" : "1px solid #eee", background: filter === t ? "#e55a7b" : "#fff", color: filter === t ? "#fff" : "#64748b", cursor: "pointer", textTransform: "capitalize" }}>{t}</button>
            ))}
          </div>
          <button onClick={fetchRides} style={{ background: "none", border: "1px solid #eee", padding: "8px", borderRadius: "8px" }}>
            <RefreshCcw size={18} className={isRefreshing ? "spin" : ""} />
          </button>
        </div>

        <div style={{ overflowX: "auto" }}>
          <table style={{ width: "100%", borderCollapse: "collapse" }}>
            <thead style={{ background: "#f8fafc", textAlign: "left" }}>
              <tr>
                <th style={{ padding: "15px" }}>Passenger</th>
                <th style={{ padding: "15px" }}>Route</th>
                <th style={{ padding: "15px" }}>Status</th>
                <th style={{ padding: "15px" }}>Actions</th>
              </tr>
            </thead>
            <tbody>
              {filteredRides.map(ride => (
                <tr key={ride.id} style={{ borderBottom: "1px solid #f1f5f9" }}>
                  <td style={{ padding: "15px" }}>
                    <div style={{ fontWeight: "600" }}>{ride.passenger_name}</div>
                    <div style={{ fontSize: "12px", color: "#64748b" }}><Phone size={10}/> {ride.phone_number}</div>
                    {ride.alt_phone && <div style={{ fontSize: "12px", color: "#94a3b8" }}><Smartphone size={10}/> {ride.alt_phone}</div>}
                  </td>
                  <td style={{ padding: "15px" }}>
                    <div style={{ fontSize: "13px" }}><MapPin size={12} color="green"/> {ride.pickup_location}</div>
                    <div style={{ fontSize: "13px" }}><MapPin size={12} color="red"/> {ride.drop_location}</div>
                  </td>
                  <td style={{ padding: "15px" }}>
                    <span style={styles.statusBadge(ride.status)}>{ride.status}</span>
                  </td>
                  <td style={{ padding: "15px" }}>
                    <div style={{ display: "flex", gap: "10px" }}>
                      <button title="Confirm Ride" onClick={() => updateStatus(ride.id, 'confirmed')} style={styles.actionBtn}><Send size={16} color="#3b82f6"/></button>
                      <button title="Mark Complete" onClick={() => updateStatus(ride.id, 'completed')} style={styles.actionBtn}><CheckCircle size={16} color="#10b981"/></button>
                      <button title="Cancel" onClick={() => updateStatus(ride.id, 'cancelled')} style={styles.actionBtn}><XCircle size={16} color="#ef4444"/></button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
      <style>{` .spin { animation: rotate 1s linear infinite; } @keyframes rotate { 100% { transform: rotate(360deg); } } `}</style>
    </div>
  );
};

export default Dashboard;
